# Who has Reader at subscription scope or higher?
Get-AzRoleAssignment -RoleDefinitionName 'Reader' |
    Where-Object { $_.Scope -match '^/subscriptions/[^/]+$' -or $_.Scope -match 'managementGroups' } |
    Select-Object DisplayName, ObjectType, Scope | Format-Table

# Find Guest users with Reader (external access visibility review)
Get-AzRoleAssignment -RoleDefinitionName 'Reader' |
    Where-Object { $_.ObjectType -eq 'User' } |
    ForEach-Object {
        $u = Get-MgUser -UserId $_.ObjectId -ErrorAction SilentlyContinue
        if ($u -and $u.UserType -eq 'Guest') {
            [PSCustomObject]@{ Name=$u.DisplayName; UPN=$u.UserPrincipalName; Scope=$_.Scope }
        }
    } | Format-Table

# Reader is the minimum required for Azure Portal navigation.
# Without at least Reader somewhere, users see a blank portal.
# Grant Reader at the RG level for external contractors who need limited visibility.
